  3→import { useState, useEffect } from "react";
  4→import { useAccount } from "wagmi";
  5→import { SelfVerification } from "@/components/self-verification";
  6→import { LendingDashboard } from "@/components/lending-dashboard";
  7→
  8→const STEPS = [
  9→  { id: "verify", label: "Verify" },
 10→  { id: "lend-borrow", label: "Lend & Borrow" },
 11→  { id: "monitor", label: "Monitor" },
 12→] as const;
 13→
 14→type Step = (typeof STEPS)[number]["id"];
 15→
 16→export function DeployAgent() {
 17→  const { address } = useAccount();
 18→  const [step, setStep] = useState<Step>("verify");
 19→  const [isVerified, setIsVerified] = useState(false);
 20→  const [checkingVerification, setCheckingVerification] = useState(false);
 21→
 22→  // Check if user is already verified on mount
 23→  useEffect(() => {
 24→    if (!address) return;
 25→
 26→    const checkVerification = async () => {
 27→      setCheckingVerification(true);
 28→      try {
 29→        const res = await fetch(`/api/verify?address=${address}`);
 30→        const data = await res.json();
 31→        if (data.verified) {
 32→          setIsVerified(true);
 33→          setStep("lend-borrow");
 34→        }
 35→      } catch {
 36→        // Not verified yet
 37→      } finally {
 38→        setCheckingVerification(false);
 39→      }
 40→    };
 41→
 42→    checkVerification();
 43→  }, [address]);
 44→
 45→  const handleVerificationSuccess = () => {
 46→    setIsVerified(true);
 47→    setStep("lend-borrow");
 48→  };
 49→
 50→  const currentIdx = STEPS.findIndex((x) => x.id === step);
 51→
 52→  if (!address) {
 53→    return (
 54→      <div className="mx-auto max-w-md text-center">
 55→        <h3 className="font-serif text-2xl text-ink">Connect your wallet.</h3>
 56→        <p className="mt-4 text-sm leading-relaxed text-ink-light">
 57→          Connect your wallet to verify your identity and access the lending
 58→          pool on Celo.
 59→        </p>
 60→      </div>
 61→    );
 62→  }
 63→
 64→  if (checkingVerification) {
 65→    return (
 66→      <div className="mx-auto max-w-md text-center">
 67→        <p className="text-sm text-ink-light">Checking verification status...</p>
 68→      </div>
 69→    );
 70→  }
 71→
 72→  return (
 73→    <div className="space-y-12">
 74→      {/* Step indicator */}
 75→      <div className="flex items-center gap-3">
 76→        {STEPS.map((s, i) => {
 77→          const isDone = currentIdx > i;
 78→          const isCurrent = step === s.id;
 79→          return (
 80→            <div key={s.id} className="flex items-center gap-3">
 81→              <div className="flex items-center gap-2">
 82→                <span
 83→                  className={`font-mono text-xs ${isCurrent ? "text-ink" : isDone ? "text-ink-light" : "text-ink-lighter"}`}
 84→                >
 85→                  {isDone ? "\u2713" : `0${i + 1}`}
 86→                </span>
 87→                <button
 88→                  onClick={() => {
 89→                    if (isDone || isCurrent) setStep(s.id);
