# QRCode SDK Integration Examples

## Installation Methods

Three package managers are supported:
- `npm i @selfxyz/qrcode`
- `yarn add @selfxyz/core`
- `pnpm i @selfxyz/qrcode`

## Desktop Implementation

The primary example demonstrates setting up identity verification on web:

```tsx
import { useEffect, useState } from 'react'
import { countries, SelfQRcodeWrapper } from '@selfxyz/qrcode'
import { SelfAppBuilder } from '@selfxyz/qrcode'

export default function Verify() {
  const [selfApp, setSelfApp] = useState<any | null>(null)

  useEffect(() => {
    const userId = '0xYourUserEthAddress'

    const app = new SelfAppBuilder({
      version: 2,
      appName: process.env.NEXT_PUBLIC_SELF_APP_NAME || 'Self Docs',
      scope: process.env.NEXT_PUBLIC_SELF_SCOPE || 'self-docs',
      endpoint: `${process.env.NEXT_PUBLIC_SELF_ENDPOINT}`,
      logoBase64: 'https://i.postimg.cc/mrmVf9hm/self.png',
      userId,
      endpointType: 'staging_celo',
      userIdType: 'hex',
      userDefinedData: 'Hello from the Docs!!',
      disclosures: {
        minimumAge: 18,
        excludedCountries: [countries.CUBA, countries.IRAN, countries.NORTH_KOREA, countries.RUSSIA],
        nationality: true,
        gender: true,
      },
    }).build()

    setSelfApp(app)
  }, [])

  const handleSuccessfulVerification = () => {
    console.log('Verified!')
  }

  return (
    <div>
      {selfApp ? (
        <SelfQRcodeWrapper
          selfApp={selfApp}
          onSuccess={handleSuccessfulVerification}
          onError={() => { console.error('Error: Failed to verify identity') }}
        />
      ) : (
        <p>Loading QR Code...</p>
      )}
    </div>
  )
}
```

## Mobile Implementation

Mobile requires deeplink configuration instead of QR scanning:

```tsx
import { useEffect, useState } from 'react'
import { countries, SelfQRcodeWrapper } from '@selfxyz/qrcode'
import { SelfAppBuilder } from '@selfxyz/qrcode'

export default function Verify() {
  const [selfApp, setSelfApp] = useState<any | null>(null)
  const [universalLink, setUniversalLink] = useState("")

  useEffect(() => {
    const userId = '0xYourUserEthAddress'

    const app = new SelfAppBuilder({
      deeplinkCallback: "https://your-callback-url.com",
    }).build()

    setSelfApp(app)
    setUniversalLink(getUniversalLink(app))
  }, [])

  const openSelfApp = () => {
    if (!universalLink) return
    window.open(universalLink, "_blank")
  }

  return (
    <div>
      {selfApp ? (
        <button type="button" onClick={openSelfApp} disabled={!universalLink}>
          Open Self App
        </button>
      ) : (
        <p>Loading QR Code...</p>
      )}
    </div>
  )
}
```

## Key Configuration Parameters

**SelfAppBuilder accepts**:
- `version`, `appName`, `scope`, `endpoint`
- `logoBase64`, `userId`, `endpointType`, `userIdType`
- `userDefinedData`, `deeplinkCallback`
- `disclosures` object with age, country restrictions, and data claims

