  process.env.SELF_AGENT_API_BASE || "https://self-agent-id.vercel.app";

export async function GET(req: NextRequest) {
  const sessionToken = req.nextUrl.searchParams.get("token");

  if (!sessionToken) {
    return NextResponse.json(
      { error: "Missing token parameter" },
      { status: 400 }
    );
  }

  try {
    const res = await fetch(
      `${SELF_AGENT_API_BASE}/api/agent/register/status?token=${encodeURIComponent(sessionToken)}`,
      {
        headers: { "Content-Type": "application/json" },
      }
    );

    const data = await res.json();
    return NextResponse.json(data);
  } catch (err) {
    const message =
      err instanceof Error ? err.message : "Status check failed";
    console.error("[agent-id/status] Error:", message);
    return NextResponse.json({ error: message }, { status: 500 });
  }
}

