"use client";

import { useCallback, useMemo } from "react";
import { SelfQRcodeWrapper, SelfAppBuilder } from "@selfxyz/qrcode";

interface SelfVerificationProps {
  walletAddress: string;
  onSuccess: () => void;
}

export function SelfVerification({
  walletAddress,
  onSuccess,
}: SelfVerificationProps) {
  const selfApp = useMemo(() => {
    if (!walletAddress) return null;
    return new SelfAppBuilder({
      appName: "OpenClaw Microlending",
      scope: "openclaw-lending",
      endpoint: process.env.NEXT_PUBLIC_SELF_ENDPOINT || "/api/verify",
      userId: walletAddress,
      userIdType: "hex",
      disclosures: {
        minimumAge: 18,
        ofac: true,
      },
    }).build();
  }, [walletAddress]);

  const handleSuccess = useCallback(() => {
    onSuccess();
  }, [onSuccess]);

  if (!selfApp) {
    return (
      <div className="space-y-8">
        <p className="text-sm text-ink-light">Connect your wallet to verify your identity.</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div>
        <h3 className="font-serif text-2xl text-ink">Verify your identity.</h3>
        <p className="mt-4 text-sm leading-relaxed text-ink-light">
          Scan the QR code with the Self app to verify your identity. This
          confirms you are 18+ and not on any sanctions list. Your personal data
          stays on your device.
        </p>
      </div>

      <div className="flex justify-center">
        <div className="rounded-lg border border-cream-dark bg-white p-6">
          <SelfQRcodeWrapper
            selfApp={selfApp}
            onSuccess={handleSuccess}
            onError={(error) => console.error("[self-verify]", error)}
            size={280}
          />
        </div>
      </div>

      <div className="space-y-3 border-t border-cream-dark pt-6">
        <div className="flex gap-4">
          <span className="font-mono text-sm text-ink-lighter">01</span>
          <span className="text-sm text-ink">
            Open the Self app on your phone
          </span>
        </div>
        <div className="flex gap-4">
          <span className="font-mono text-sm text-ink-lighter">02</span>
          <span className="text-sm text-ink">Scan the QR code above</span>
        </div>
        <div className="flex gap-4">
          <span className="font-mono text-sm text-ink-lighter">03</span>
          <span className="text-sm text-ink">
            Approve the verification request
          </span>
        </div>
      </div>

      <p className="text-xs text-ink-lighter">
        Powered by Self protocol. Zero-knowledge identity verification — no
        personal data is shared with the lending pool.
      </p>
    </div>
  );
}

