"use client";

import { useState, useEffect } from "react";
import { useAccount } from "wagmi";
import { SelfVerification } from "@/components/self-verification";
import { LendingDashboard } from "@/components/lending-dashboard";

const STEPS = [
  { id: "verify", label: "Verify" },
  { id: "lend-borrow", label: "Lend & Borrow" },
  { id: "monitor", label: "Monitor" },
] as const;

type Step = (typeof STEPS)[number]["id"];

export function DeployAgent() {
  const { address } = useAccount();
  const [step, setStep] = useState<Step>("verify");
  const [isVerified, setIsVerified] = useState(false);
  const [checkingVerification, setCheckingVerification] = useState(false);

  // Privy agentic wallet state
  const [agentWallet, setAgentWallet] = useState<{
    walletId: string;
    address: string;
  } | null>(null);
  const [creatingWallet, setCreatingWallet] = useState(false);
  const [walletError, setWalletError] = useState<string | null>(null);

  // Create Privy agentic wallet when user connects
  useEffect(() => {
    if (!address || agentWallet) return;

    const createWallet = async () => {
      setCreatingWallet(true);
      setWalletError(null);
      try {
        const res = await fetch("/api/wallet/create", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ ownerAddress: address }),
        });
        const data = await res.json();
        if (data.error) throw new Error(data.error);
        setAgentWallet({ walletId: data.walletId, address: data.address });
      } catch (err) {
        const message =
          err instanceof Error ? err.message : "Failed to create wallet";
        setWalletError(message);
      } finally {
        setCreatingWallet(false);
      }
    };

    createWallet();
  }, [address, agentWallet]);

  // Check if user is already verified (using agent wallet address)
  useEffect(() => {
    if (!agentWallet) return;

    const checkVerification = async () => {
      setCheckingVerification(true);
      try {
        const res = await fetch(
          `/api/verify?address=${agentWallet.address}`
        );
        const data = await res.json();
        if (data.verified) {
          setIsVerified(true);
          setStep("lend-borrow");
        }
      } catch {
        // Not verified yet
      } finally {
        setCheckingVerification(false);
      }
    };

    checkVerification();
  }, [agentWallet]);

  const handleVerificationSuccess = () => {
    setIsVerified(true);
    setStep("lend-borrow");
  };

  const currentIdx = STEPS.findIndex((x) => x.id === step);

  if (!address) {
    return (
      <div className="mx-auto max-w-md text-center">
        <h3 className="font-serif text-2xl text-ink">Connect your wallet.</h3>
        <p className="mt-4 text-sm leading-relaxed text-ink-light">
          Connect your wallet to verify your identity and access the lending
          pool on Celo.
        </p>
      </div>
    );
  }

  if (creatingWallet) {
    return (
      <div className="mx-auto max-w-md text-center">
        <p className="text-sm text-ink-light">
          Creating your agentic wallet on Celo...
        </p>
      </div>
    );
  }

  if (walletError) {
    return (
      <div className="mx-auto max-w-md text-center">
        <div className="rounded border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-800">
          {walletError}
        </div>
        <button
          onClick={() => {
            setAgentWallet(null);
            setWalletError(null);
          }}
          className="mt-4 font-mono text-xs text-ink-lighter hover:text-ink"
        >
          Retry
        </button>
      </div>
    );
  }

  if (!agentWallet || checkingVerification) {
    return (
      <div className="mx-auto max-w-md text-center">
        <p className="text-sm text-ink-light">
          {checkingVerification
            ? "Checking verification status..."
            : "Setting up..."}
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-12">
      {/* Agent wallet info */}
      <div className="flex items-center justify-between border-b border-cream-dark pb-4">
        <div>
          <span className="font-mono text-xs uppercase tracking-[0.15em] text-ink-lighter">
            Agent Wallet
          </span>
          <p className="mt-1 font-mono text-sm text-ink">
            {agentWallet.address.slice(0, 6)}...
            {agentWallet.address.slice(-4)}
          </p>
        </div>
        <div>
          <span className="font-mono text-xs uppercase tracking-[0.15em] text-ink-lighter">
            Network
          </span>
          <p className="mt-1 font-mono text-sm text-ink">Celo</p>
        </div>
      </div>

      {/* Step indicator */}
      <div className="flex items-center gap-3">
        {STEPS.map((s, i) => {
          const isDone = currentIdx > i;
          const isCurrent = step === s.id;
          return (
            <div key={s.id} className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <span
                  className={`font-mono text-xs ${isCurrent ? "text-ink" : isDone ? "text-ink-light" : "text-ink-lighter"}`}
                >
                  {isDone ? "\u2713" : `0${i + 1}`}
                </span>
                <button
                  onClick={() => {
                    if (isDone || isCurrent) setStep(s.id);
                  }}
                  disabled={!isDone && !isCurrent}
                  className={`font-mono text-xs uppercase tracking-wider ${isCurrent ? "text-ink" : isDone ? "text-ink-light cursor-pointer hover:text-ink" : "text-ink-lighter"}`}
                >
                  {s.label}
                </button>
              </div>
              {i < STEPS.length - 1 && (
                <div className="h-px w-12 bg-cream-dark" />
              )}
            </div>
          );
        })}
      </div>

      {/* Step 1: Verify */}
      {step === "verify" && (
        <div className="mx-auto max-w-md">
          <SelfVerification
            walletAddress={agentWallet.address}
            onSuccess={handleVerificationSuccess}
          />

          {/* Skip verification for lending-only (optional) */}
          <div className="mt-8 border-t border-cream-dark pt-6">
            <button
              onClick={() => setStep("lend-borrow")}
              className="font-mono text-xs text-ink-lighter hover:text-ink"
            >
              Skip verification (lending only, no borrowing)
            </button>
          </div>
        </div>
      )}

      {/* Step 2: Lend & Borrow */}
      {step === "lend-borrow" && (
        <LendingDashboard
          walletAddress={agentWallet.address}
          isVerified={isVerified}
        />
      )}

      {/* Step 3: Monitor */}
      {step === "monitor" && (
        <LendingDashboard
          walletAddress={agentWallet.address}
          isVerified={isVerified}
        />
      )}

      {/* Navigation */}
      {step === "lend-borrow" && (
        <div className="flex gap-4">
          <button
            onClick={() => setStep("verify")}
            className="border border-cream-dark px-8 py-4 font-mono text-sm uppercase tracking-wider text-ink-light transition-colors hover:border-ink hover:text-ink"
          >
            Back to Verify
          </button>
          <button
            onClick={() => setStep("monitor")}
            className="bg-ink px-8 py-4 font-mono text-sm uppercase tracking-wider text-cream transition-opacity hover:opacity-80"
          >
            View Monitor
          </button>
        </div>
      )}
    </div>
  );
}

import { NextRequest, NextResponse } from "next/server";
import { requestRegistration } from "@selfxyz/agent-sdk";

export async function POST(req: NextRequest) {
  try {
    const { humanAddress, agentName } = await req.json();

    if (!humanAddress) {
      return NextResponse.json(
        { error: "Missing humanAddress" },
        { status: 400 }
      );
    }

    const session = await requestRegistration({
      mode: "linked",
      network: "testnet",
      humanAddress,
      agentName: agentName || "OpenClaw Lending Agent",
      agentDescription: "Microlending agent on Celo with Self-verified identity",
      disclosures: {
        minimumAge: 18,
        ofac: true,
      },
    });

    return NextResponse.json({
      sessionToken: session.sessionToken,
      deepLink: session.deepLink,
      agentAddress: session.agentAddress,
      expiresAt: session.expiresAt,
      stage: session.stage,
      humanInstructions: session.humanInstructions,
    });
  } catch (err) {
    const message =
      err instanceof Error ? err.message : "Registration failed";
    console.error("[agent-id/register] Error:", message);
    return NextResponse.json({ error: message }, { status: 500 });
  }
}

