import { NextRequest, NextResponse } from "next/server";
import { requestRegistration } from "@selfxyz/agent-sdk";

// Store active sessions server-side so waitForCompletion can track rolling tokens
const activeSessions = new Map<
  string,
  {
    session: Awaited<ReturnType<typeof requestRegistration>>;
    result: { status: string; agentId?: number; agentAddress?: string; txHash?: string; privateKey?: string } | null;
    error: string | null;
  }
>();

export async function POST(req: NextRequest) {
  try {
    const { humanAddress, agentName } = await req.json();

    if (!humanAddress) {
      return NextResponse.json(
        { error: "Missing humanAddress" },
        { status: 400 }
      );
    }

    const session = await requestRegistration({
      mode: "linked",
      network: "mainnet",
      humanAddress,
      agentName: agentName || "OpenClaw Lending Agent",
      agentDescription:
        "Microlending agent on Celo with Self-verified identity",
      disclosures: {
        minimumAge: 18,
        ofac: true,
      },
    });

    const sessionKey = session.sessionToken.slice(0, 32);

    // Store session and start waiting in background
    const entry = {
      session,
      result: null as typeof activeSessions extends Map<string, infer V> ? V["result"] : never,
      error: null as string | null,
    };
    activeSessions.set(sessionKey, entry);

    // Wait for completion in background (5 min timeout)
    session
