import { NextRequest, NextResponse } from "next/server";
import { requestRegistration } from "@selfxyz/agent-sdk";

// Store active sessions server-side so waitForCompletion can track rolling tokens
const activeSessions = new Map<
  string,
  {
    session: Awaited<ReturnType<typeof requestRegistration>>;
    result: { status: string; agentId?: number; agentAddress?: string; txHash?: string; privateKey?: string } | null;
    error: string | null;
  }
>();

export async function POST(req: NextRequest) {
  try {
    const { humanAddress, agentName } = await req.json();

    if (!humanAddress) {
      return NextResponse.json(
        { error: "Missing humanAddress" },
        { status: 400 }
      );
    }

    const session = await requestRegistration({
      mode: "linked",
      network: "mainnet",
      humanAddress,
      agentName: agentName || "OpenClaw Lending Agent",
      agentDescription:
        "Microlending agent on Celo with Self-verified identity",
      disclosures: {
        minimumAge: 18,
        ofac: true,
      },
    });

    const sessionKey = session.sessionToken.slice(0, 32);

    // Store session and start waiting in background
    const entry = {
      session,
      result: null as { status: string; agentId?: number; agentAddress?: string; txHash?: string; privateKey?: string } | null,
      error: null as string | null,
    };
    activeSessions.set(sessionKey, entry);

    // Wait for completion in background (5 min timeout)
    session
      .waitForCompletion({ timeoutMs: 300_000, pollIntervalMs: 3000 })
      .then(async (result) => {
        // Export the agent private key
        let privateKey: string | undefined;
        try {
          privateKey = await session.exportKey();
        } catch {
          // Key export may not be available for all modes
        }

        entry.result = {
          status: "completed",
          agentId: result.agentId,
          agentAddress: result.agentAddress,
          txHash: result.txHash,
          privateKey,
        };
      })
      .catch((err) => {
        entry.error = err instanceof Error ? err.message : "Registration failed";
        entry.result = { status: "failed" };
      });

    return NextResponse.json({
      sessionKey,
      deepLink: session.deepLink,
      agentAddress: session.agentAddress,
      expiresAt: session.expiresAt,
      stage: session.stage,
      humanInstructions: session.humanInstructions,
    });
  } catch (err) {
    const message =
      err instanceof Error ? err.message : "Registration failed";
    console.error("[agent-id/register] Error:", message);
    return NextResponse.json({ error: message }, { status: 500 });
  }
}

// Poll endpoint — uses the sessionKey to check background waitForCompletion
export async function GET(req: NextRequest) {
  const sessionKey = req.nextUrl.searchParams.get("key");

  if (!sessionKey) {
    return NextResponse.json(
      { error: "Missing key parameter" },
      { status: 400 }
    );
  }

  const entry = activeSessions.get(sessionKey);
  if (!entry) {
    return NextResponse.json(
      { error: "Session not found" },
      { status: 404 }
    );
  }

  if (entry.error) {
    // Clean up
    activeSessions.delete(sessionKey);
    return NextResponse.json({
      stage: "failed",
      error: entry.error,
    });
  }

  if (entry.result && entry.result.status === "completed") {
    // Clean up
    activeSessions.delete(sessionKey);
    return NextResponse.json({
      stage: "completed",
      agentId: entry.result.agentId,
      agentAddress: entry.result.agentAddress,
      txHash: entry.result.txHash,
      privateKey: entry.result.privateKey,
    });
  }

  return NextResponse.json({
    stage: "waiting",
    agentAddress: entry.session.agentAddress,
  });
}

